PublicResourceConfig = {}
local Config = {}

local function ParsePosition(str)
    local tab = StringUtil.split(str, ",")
    local x = tonumber(tab[1]) or 0
    local y = tonumber(tab[2]) or 0
    local z = tonumber(tab[3]) or 0
    return VectorUtil.newVector3(x, y, z)
end

function PublicResourceConfig:init(configs)
    for _, config in pairs(configs) do
        if tonumber(config.mapId) == tonumber(GameConfig.mapId) then
            local data = {}
            data.id = tostring(config.id)
            data.resourcePointId = tonumber(config.resourcePointId)
            data.headInfo = tostring(config.headInfo)
            data.actor = tostring(config.actor)
            data.actorBody = tostring(config.actorBody)
            data.actorBodyId = tostring(config.actorBodyId)
            data.actorPos = ParsePosition(config.actorPos)
            Config[data.id] = data
        end
    end
end

function PublicResourceConfig:initNpcByConfig(resourceId)
    local config = Config[resourceId]
    local entityId = EngineWorld:addSessionNpc(config.actorPos, 0, -1, config.actor, function(entity)
        entity:setActorBody(config.actorBody or "body")
        entity:setActorBodyId(config.actorBodyId or "")
        entity:setCanCollided(false)
        entity:setSuspended(true, config.actorPos)
    end)
    Config[config.id].entityId = entityId
    return entityId
end

function PublicResourceConfig:updateNpcHeadInfo(entityId, pointId, level, curInterval)
    local SessionNpc = DynamicCast.dynamicCastEntity(EntityType.SessionNpc, EngineWorld:getEntity(entityId))
    SessionNpc:setHeadNameMulTickInfo(Config[pointId].headInfo, level, curInterval * 1000)
end

if GameConfig.mapId then
    PublicResourceConfig:init(FileUtil.getConfigFromCsv("setting/PublicResource.csv"))
end
